func (h *handler) CancelSubscription() CancelSubscriptionHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params CancelSubscriptionParams) (CancelSubscriptionRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return CancelSubscriptionRequest{}, err }
			var body api.CancelSubscriptionJSONRequestBody
			if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil { return CancelSubscriptionRequest{}, err }
			timing, err := MapAPITimingToTiming(*body.Timing)
			if err != nil { return CancelSubscriptionRequest{}, models.NewGenericValidationError(err) }
			return CancelSubscriptionRequest{Timing: timing, ID: models.NamespacedID{Namespace: ns, ID: params.ID}}, nil
		},
		func(ctx context.Context, req CancelSubscriptionRequest) (CancelSubscriptionResponse, error) {
			sub, err := h.SubscriptionService.Cancel(ctx, req.ID, req.Timing)
			if err != nil { return CancelSubscriptionResponse{}, err }
			return MapSubscriptionToAPI(sub), nil
		},
		commonhttp.JSONResponseEncoderWithStatus[CancelSubscriptionResponse](http.StatusOK),
		httptransport.AppendOptions(h.Options, httptransport.WithOperationName("cancelSubscription"), httptransport.WithErrorEncoder(errorEncoder()))...,
	)
}

func (s *service) Change(ctx context.Context, request plansubscription.ChangeSubscriptionRequest) (plansubscription.SubscriptionChangeResponse, error) {
	var def plansubscription.SubscriptionChangeResponse
	if err := request.PlanInput.Validate(); err != nil { return def, models.NewGenericValidationError(err) }
	var plan subscription.Plan
	if request.PlanInput.AsRef() != nil {
		p, err := s.getPlanByVersion(ctx, request.ID.Namespace, *request.PlanInput.AsRef())
		if err != nil { return def, err }
		now := clock.Now()
		if p.StatusAt(now) != productcatalog.PlanStatusActive { return def, models.NewGenericValidationError(fmt.Errorf("plan %s@%d is not active", p.Key, p.Version)) }
		plan = PlanFromPlan(*p)
	}
	curr, next, err := s.WorkflowService.ChangeToPlan(ctx, request.ID, request.WorkflowInput, plan)
	if err != nil { return def, err }
	return plansubscription.SubscriptionChangeResponse{Current: curr, Next: next}, nil
}
